#include <iostream>
#include <string>

class Player {
private:
    // Private: only accessible inside the class
    std::string name;
    int health;
    int maxHealth;
    int attack;
    int defense;

protected:
    // Protected: accessible in this class and derived classes
    int level;
    double experience;

public:
    // Public: accessible from anywhere
    Player(std::string n, int h, int a, int d) {
        name = n;
        health = h;
        maxHealth = h;
        attack = a;
        defense = d;
        level = 1;
        experience = 0;
    }

    // Public methods to access private data
    std::string getName() const { return name; }
    int getHealth() const { return health; }
    int getMaxHealth() const { return maxHealth; }
    int getAttack() const { return attack; }
    int getDefense() const { return defense; }

    void takeDamage(int damage) {
        int actualDamage = damage - (defense / 2);
        if (actualDamage < 0) actualDamage = 0;
        health -= actualDamage;
        std::cout << name << " took " << actualDamage << " damage!" << std::endl;
        if (health < 0) health = 0;
    }

    void heal(int amount) {
        health += amount;
        if (health > maxHealth) health = maxHealth;
        std::cout << name << " healed " << amount << " HP!" << std::endl;
    }

    // Protected method (accessible in derived classes)
    void gainExperience(double exp) {
        experience += exp;
        std::cout << name << " gained " << exp << " XP!" << std::endl;

        int requiredExp = level * 100;
        if (experience >= requiredExp) {
            level++;
            maxHealth += 20;
            health = maxHealth;
            attack += 5;
            defense += 3;
            std::cout << name << " reached level " << level << "!" << std::endl;
            experience = 0;
        }
    }

    void displayStats() const {
        std::cout << "\n=== Player Stats ===" << std::endl;
        std::cout << "Name: " << name << std::endl;
        std::cout << "Level: " << level << std::endl;
        std::cout << "Health: " << health << "/" << maxHealth << std::endl;
        std::cout << "Attack: " << attack << std::endl;
        std::cout << "Defense: " << defense << std::endl;
        std::cout << "Experience: " << experience << std::endl;
    }
};

// Derived class (inherits from Player)
class Warrior : public Player {
public:
    Warrior(std::string n, int h, int a, int d) : Player(n, h, a, d) {}

    void specialAttack() {
        // Can access protected members from Player
        std::cout << getName() << " uses a special attack!" << std::endl;
        gainExperience(30);  // Protected method
        std::cout << "Current level: " << level << std::endl;  // Protected field
    }

    // Can't access private members directly!
    // void showHealth() { std::cout << health; } // ERROR!
};

int main() {
    std::cout << "=== Access Modifiers ===" << std::endl;

    Player hero("Aragorn", 120, 25, 15);
    hero.displayStats();

    // Public members are accessible
    std::cout << "\nName (public getter): " << hero.getName() << std::endl;

    // Private members are NOT accessible directly
    // hero.name = "Bob";  // ERROR!
    // hero.health = 999;  // ERROR!

    // Use public methods to modify private data
    hero.takeDamage(30);
    hero.heal(20);
    hero.displayStats();

    // Protected members are NOT accessible outside the class
    // hero.level = 5;  // ERROR!
    // hero.gainExperience(50);  // ERROR!

    // But derived classes can access protected members
    Warrior w("Conan", 150, 30, 20);
    w.specialAttack();

    return 0;
}

